CREATE TABLE users (id BIGSERIAL PRIMARY KEY, telegram_id TEXT UNIQUE, phone TEXT UNIQUE, name TEXT, balance NUMERIC DEFAULT 0, lifetime_earnings NUMERIC DEFAULT 0, upi_id TEXT, bank_account TEXT, bank_ifsc TEXT, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE conversions (id BIGSERIAL PRIMARY KEY, user_id TEXT, offer_name TEXT, event TEXT, amount NUMERIC DEFAULT 0, comment TEXT, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE withdrawals (id BIGSERIAL PRIMARY KEY, telegram_id TEXT, request_id TEXT UNIQUE, amount NUMERIC, method TEXT, upi_id TEXT, bank_account TEXT, bank_ifsc TEXT, status TEXT DEFAULT 'pending', created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE clicks (id BIGSERIAL PRIMARY KEY, click_id TEXT, offer_name TEXT, created_at TIMESTAMP DEFAULT NOW()); CREATE TABLE offer_status (id BIGSERIAL PRIMARY KEY, offer_name TEXT UNIQUE, is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW());
